{{TemplateData header}}
<templatedata>
{
    "params": {
        "1": {
            "label": "Scope (e.g. section)",
            "description": "This parameter allows an editor to replace the default word \"article\" with another word, usually \"section\"",
            "type": "content",
            "default": "article"
        },
        "type": {
            "autovalue": "",
            "aliases": [
                "2"
            ],
            "label": "Type",
            "description": "To replace the text \"promotional content\" with another phrase",
            "type": "content",
            "default": "promotional content"
        },
        "date": {
            "label": "Month and year",
            "description": "Month and year of tagging; e.g., 'January 2013', but not 'jan13'",
            "type": "string",
            "autovalue": "May 2025",
            "suggested": true
        }
    },
    "format": "inline",
    "description": "Template for articles with promotional content"
}
</templatedata>

